import { useState, useEffect, useCallback } from "react";

// ─── CONFIG ──────────────────────────────────────────────────────────────────
const DEFAULT_BASE = "http://localhost:8189";

// ─── ADMIN PANEL DATA ────────────────────────────────────────────────────────
const SECTIONS = [
  {
    name: "/boards", color: "#7F77DD",
    endpoints: [
      { method: "GET", path: "/boards/all" },
      { method: "GET", path: "/boards/{id}", hasId: true },
      { method: "POST", path: "/boards/create" },
    ],
  },
  {
    name: "/posts", color: "#1D9E75",
    endpoints: [
      { method: "GET", path: "/posts/all" },
      { method: "GET", path: "/posts/{id}", hasId: true },
      { method: "POST", path: "/posts/create" },
    ],
  },
  {
    name: "/threads", color: "#D85A30",
    endpoints: [
      { method: "GET", path: "/threads/all" },
      { method: "GET", path: "/threads/{id}", hasId: true },
      { method: "POST", path: "/threads/create" },
    ],
  },
  {
    name: "/fakers", color: "#BA7517",
    endpoints: [
      { method: "GET", path: "/fakers/generate" },
      { method: "GET", path: "/posts/generateFakePost" },
      { method: "GET", path: "/boards/generateFakeBoard" },
      { method: "GET", path: "/threads/generateFakeThread" },
      { method: "GET", path: "/threads/threadFactory" },
    ],
  },
];

// ─── STYLES ──────────────────────────────────────────────────────────────────
const styles = `
  :root {
    --bg: #ffffff;
    --bg2: #f5f5f3;
    --bg3: #efefec;
    --text: #1a1a18;
    --muted: #888780;
    --hint: #b4b2a9;
    --border: rgba(0,0,0,0.12);
    --border2: rgba(0,0,0,0.22);
    --danger: #a32d2d;
    --accent: #7F77DD;
    --radius: 8px;
    --radius-lg: 12px;
  }
  @media (prefers-color-scheme: dark) {
    :root {
      --bg: #1e1e1c;
      --bg2: #2a2a28;
      --bg3: #333330;
      --text: #e8e6df;
      --muted: #888780;
      --hint: #5f5e5a;
      --border: rgba(255,255,255,0.1);
      --border2: rgba(255,255,255,0.2);
      --danger: #f09595;
      --accent: #9d97e8;
    }
  }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: 'Courier New', monospace; background: var(--bg3); color: var(--text); min-height: 100vh; }

  /* ── HEADER ── */
  .ib-header {
    background: var(--bg);
    border-bottom: 1px solid var(--border2);
    padding: 0 1rem;
    position: sticky;
    top: 0;
    z-index: 100;
  }
  .ib-header-inner {
    max-width: 960px;
    margin: 0 auto;
    display: flex;
    align-items: center;
    gap: 1rem;
    height: 44px;
  }
  .ib-logo {
    font-size: 15px;
    font-weight: 700;
    letter-spacing: -0.03em;
    color: var(--accent);
    cursor: pointer;
    white-space: nowrap;
    user-select: none;
  }
  .ib-logo span { color: var(--text); }
  .ib-breadcrumb {
    display: flex;
    align-items: center;
    gap: 4px;
    font-size: 11px;
    color: var(--muted);
    overflow: hidden;
  }
  .ib-breadcrumb-sep { color: var(--hint); }
  .ib-breadcrumb-link {
    cursor: pointer;
    color: var(--accent);
    text-decoration: none;
    white-space: nowrap;
  }
  .ib-breadcrumb-link:hover { text-decoration: underline; }
  .ib-breadcrumb-cur { color: var(--muted); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
  .ib-nav-spacer { flex: 1; }
  .ib-nav-tabs { display: flex; gap: 2px; }
  .ib-tab {
    font-family: inherit;
    font-size: 11px;
    padding: 4px 10px;
    border: 0.5px solid transparent;
    border-radius: var(--radius);
    background: transparent;
    color: var(--muted);
    cursor: pointer;
    transition: all 0.12s;
    white-space: nowrap;
  }
  .ib-tab:hover { background: var(--bg2); color: var(--text); }
  .ib-tab.active { background: var(--bg3); color: var(--text); border-color: var(--border2); }

  /* ── LAYOUT ── */
  .ib-main { max-width: 960px; margin: 0 auto; padding: 1.5rem 1rem; }

  /* ── HOME PAGE ── */
  .home-banner {
    background: var(--bg);
    border: 0.5px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 1.5rem;
    margin-bottom: 1.5rem;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 1rem;
  }
  .home-banner-title {
    font-size: 22px;
    font-weight: 700;
    letter-spacing: -0.04em;
    color: var(--text);
  }
  .home-banner-sub {
    font-size: 11px;
    color: var(--muted);
    margin-top: 4px;
  }
  .home-banner-tag {
    font-size: 10px;
    padding: 3px 10px;
    border-radius: 99px;
    background: var(--bg3);
    border: 0.5px solid var(--border2);
    color: var(--muted);
    white-space: nowrap;
  }
  .boards-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
    gap: 10px;
  }
  .board-card {
    background: var(--bg);
    border: 0.5px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 1rem;
    cursor: pointer;
    transition: border-color 0.12s, transform 0.1s;
    position: relative;
    overflow: hidden;
  }
  .board-card::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 2px;
    background: var(--accent);
    opacity: 0;
    transition: opacity 0.12s;
  }
  .board-card:hover { border-color: var(--border2); transform: translateY(-1px); }
  .board-card:hover::before { opacity: 1; }
  .board-card:active { transform: scale(0.99); }
  .board-tag {
    font-size: 10px;
    color: var(--hint);
    text-transform: uppercase;
    letter-spacing: 0.1em;
    margin-bottom: 6px;
  }
  .board-name {
    font-size: 14px;
    font-weight: 700;
    margin-bottom: 4px;
    letter-spacing: -0.02em;
  }
  .board-desc {
    font-size: 11px;
    color: var(--muted);
    line-height: 1.5;
    overflow: hidden;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
  }
  .board-meta {
    margin-top: 10px;
    display: flex;
    gap: 8px;
    align-items: center;
  }
  .board-stat {
    font-size: 10px;
    color: var(--hint);
    display: flex;
    align-items: center;
    gap: 3px;
  }

  /* ── BOARD PAGE ── */
  .page-header {
    background: var(--bg);
    border: 0.5px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 1.2rem 1.5rem;
    margin-bottom: 1rem;
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 1rem;
  }
  .page-title {
    font-size: 18px;
    font-weight: 700;
    letter-spacing: -0.03em;
  }
  .page-sub {
    font-size: 11px;
    color: var(--muted);
    margin-top: 3px;
  }
  .thread-list { display: flex; flex-direction: column; gap: 8px; }
  .thread-card {
    background: var(--bg);
    border: 0.5px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 1rem 1.2rem;
    cursor: pointer;
    transition: border-color 0.12s;
    display: flex;
    align-items: flex-start;
    gap: 12px;
  }
  .thread-card:hover { border-color: var(--border2); }
  .thread-num {
    font-size: 10px;
    color: var(--hint);
    min-width: 28px;
    margin-top: 2px;
    flex-shrink: 0;
  }
  .thread-body { flex: 1; min-width: 0; }
  .thread-title {
    font-size: 13px;
    font-weight: 600;
    margin-bottom: 4px;
    letter-spacing: -0.01em;
  }
  .thread-preview {
    font-size: 11px;
    color: var(--muted);
    overflow: hidden;
    white-space: nowrap;
    text-overflow: ellipsis;
  }
  .thread-arrow {
    font-size: 16px;
    color: var(--hint);
    flex-shrink: 0;
    margin-top: 2px;
    transition: color 0.12s;
  }
  .thread-card:hover .thread-arrow { color: var(--muted); }

  /* ── THREAD PAGE ── */
  .post-list { display: flex; flex-direction: column; gap: 1px; }
  .post-card {
    background: var(--bg);
    border: 0.5px solid var(--border);
    padding: 0.9rem 1.2rem;
    position: relative;
  }
  .post-card:first-child { border-radius: var(--radius-lg) var(--radius-lg) 0 0; }
  .post-card:last-child { border-radius: 0 0 var(--radius-lg) var(--radius-lg); }
  .post-card:only-child { border-radius: var(--radius-lg); }
  .post-card:not(:last-child) { border-bottom: none; }
  .post-head {
    display: flex;
    align-items: center;
    gap: 8px;
    margin-bottom: 8px;
    flex-wrap: wrap;
  }
  .post-id {
    font-size: 10px;
    color: var(--hint);
  }
  .post-author {
    font-size: 12px;
    font-weight: 600;
    color: var(--accent);
  }
  .post-date {
    font-size: 10px;
    color: var(--hint);
    margin-left: auto;
  }
  .post-no {
    font-size: 10px;
    color: var(--hint);
    padding: 1px 6px;
    background: var(--bg3);
    border-radius: 4px;
  }
  .post-body {
    font-size: 12px;
    line-height: 1.7;
    color: var(--text);
    white-space: pre-wrap;
    word-break: break-word;
  }
  .post-greentext {
    color: #27500A;
  }
  @media (prefers-color-scheme: dark) {
    .post-greentext { color: #7ec85a; }
  }

  /* ── SHARED ── */
  .section-label {
    font-size: 10px;
    color: var(--hint);
    text-transform: uppercase;
    letter-spacing: 0.1em;
    margin-bottom: 10px;
  }
  .empty-state {
    background: var(--bg);
    border: 0.5px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 3rem;
    text-align: center;
    color: var(--muted);
    font-size: 12px;
  }
  .loading-state {
    background: var(--bg);
    border: 0.5px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 2rem;
    text-align: center;
    color: var(--hint);
    font-size: 12px;
  }
  .error-state {
    background: var(--bg);
    border: 0.5px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 1.5rem;
    color: var(--danger);
    font-size: 12px;
  }
  .count-pill {
    font-size: 10px;
    padding: 2px 8px;
    border-radius: 99px;
    background: var(--bg3);
    border: 0.5px solid var(--border);
    color: var(--muted);
    white-space: nowrap;
  }

  /* ── ADMIN PANEL (existing styles) ── */
  .app { max-width: 900px; margin: 0 auto; padding: 2rem 1rem; }
  .top-bar { display: flex; gap: 8px; align-items: center; margin-bottom: 1.5rem; }
  .base-input { flex: 1; font-family: inherit; font-size: 13px; padding: 7px 10px; border: 0.5px solid var(--border2); border-radius: var(--radius); background: var(--bg); color: var(--text); }
  .base-input:focus { outline: none; border-color: var(--muted); }
  .badge { font-size: 11px; padding: 2px 8px; border-radius: 99px; font-family: inherit; font-weight: 500; white-space: nowrap; }
  .badge-get { background: #E6F1FB; color: #0C447C; }
  .badge-post { background: #EAF3DE; color: #27500A; }
  .sections { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 12px; margin-bottom: 1.5rem; }
  .section { background: var(--bg); border: 0.5px solid var(--border); border-radius: var(--radius-lg); padding: 1rem; }
  .section-title { font-size: 12px; font-weight: 500; color: var(--muted); text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 10px; display: flex; align-items: center; gap: 6px; }
  .dot { width: 7px; height: 7px; border-radius: 50%; display: inline-block; flex-shrink: 0; }
  .btn-row { display: flex; align-items: center; gap: 6px; margin-bottom: 6px; }
  .btn-row:last-child { margin-bottom: 0; }
  .endpoint-btn { flex: 1; font-family: inherit; font-size: 12px; padding: 5px 8px; border: 0.5px solid var(--border2); border-radius: var(--radius); background: var(--bg2); color: var(--text); cursor: pointer; text-align: left; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; transition: background 0.1s; }
  .endpoint-btn:hover { background: var(--bg3); }
  .endpoint-btn:active { transform: scale(0.98); }
  .id-input { width: 60px; font-family: inherit; font-size: 12px; padding: 5px 6px; border: 0.5px solid var(--border2); border-radius: var(--radius); background: var(--bg2); color: var(--text); text-align: center; }
  .id-input:focus { outline: none; border-color: var(--muted); }
  .id-input::placeholder { color: var(--hint); font-size: 11px; }
  .response-area { background: var(--bg); border: 0.5px solid var(--border); border-radius: var(--radius-lg); padding: 1rem; min-height: 180px; }
  .response-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 10px; }
  .response-label { font-size: 12px; color: var(--muted); text-transform: uppercase; letter-spacing: 0.06em; }
  .status-pill { font-size: 11px; padding: 2px 8px; border-radius: 99px; font-family: inherit; font-weight: 500; }
  .status-ok { background: #EAF3DE; color: #27500A; }
  .status-err { background: #FCEBEB; color: #791F1F; }
  .status-idle { background: var(--bg2); color: var(--hint); border: 0.5px solid var(--border); }
  .req-line { font-size: 11px; color: var(--hint); margin-bottom: 6px; word-break: break-all; }
  .response-body { font-family: inherit; font-size: 12px; white-space: pre-wrap; word-break: break-all; line-height: 1.6; }
  .clear-btn { font-size: 11px; font-family: inherit; padding: 2px 8px; border: 0.5px solid var(--border); border-radius: var(--radius); background: transparent; color: var(--muted); cursor: pointer; }
  .clear-btn:hover { color: var(--text); border-color: var(--border2); }
`;

// ─── UTILS ───────────────────────────────────────────────────────────────────
function useApi(baseUrl) {
  const get = useCallback(async (path) => {
    const url = baseUrl.replace(/\/$/, "") + path;
    const res = await fetch(url);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return res.json();
  }, [baseUrl]);
  return { get };
}

function formatDate(val) {
  if (!val) return "";
  try {
    return new Date(val).toLocaleString("ru-RU", {
      day: "2-digit", month: "2-digit", year: "2-digit",
      hour: "2-digit", minute: "2-digit",
    });
  } catch { return String(val); }
}

// Вытаскиваем значение из объекта — API может вернуть разные структуры
function pick(obj, ...keys) {
  if (!obj || typeof obj !== "object") return undefined;
  for (const k of keys) if (obj[k] !== undefined && obj[k] !== null) return obj[k];
  return undefined;
}

function getBoardName(b) { return pick(b, "name", "title", "label", "boardName") || `Board #${b.id}`; }
function getBoardDesc(b) { return pick(b, "description", "desc", "about", "subtitle") || ""; }
function getThreadTitle(t) { return pick(t, "title", "subject", "name", "header") || `Thread #${t.id}`; }
function getThreadPreview(t) {
  const body = pick(t, "body", "content", "text", "message");
  return body ? String(body).slice(0, 80) : "";
}
function getAuthor(item) {
  // Could be a nested user object or flat fields
  const user = item.user || item.author || item.poster || {};
  return pick(user, "name", "username", "nickname", "login")
    || pick(item, "userName", "username", "authorName", "nickname", "poster", "author")
    || "Anonymous";
}
function getPostBody(p) { return pick(p, "body", "content", "text", "message") || ""; }

// Normalise list response — might be array directly or { data: [...] } etc.
function normalizeList(res) {
  if (Array.isArray(res)) return res;
  if (res && Array.isArray(res.data)) return res.data;
  if (res && Array.isArray(res.items)) return res.items;
  if (res && Array.isArray(res.content)) return res.content;
  if (res && Array.isArray(res.boards)) return res.boards;
  if (res && Array.isArray(res.threads)) return res.threads;
  if (res && Array.isArray(res.posts)) return res.posts;
  return [];
}

// ─── COMPONENTS ──────────────────────────────────────────────────────────────

// Post body with greentext rendering
function PostBody({ text }) {
  const lines = String(text).split("\n");
  return (
    <div className="post-body">
      {lines.map((line, i) => (
        <span key={i}>
          {line.startsWith(">")
            ? <span className="post-greentext">{line}</span>
            : line}
          {i < lines.length - 1 && "\n"}
        </span>
      ))}
    </div>
  );
}

function LoadingBlock() { return <div className="loading-state">загрузка...</div>; }
function ErrorBlock({ msg }) { return <div className="error-state">⚠ {msg}</div>; }
function EmptyBlock({ text }) { return <div className="empty-state">{text || "пусто"}</div>; }

// ─── HOME PAGE ───────────────────────────────────────────────────────────────
function HomePage({ api, onBoard }) {
  const [boards, setBoards] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    setLoading(true); setError(null); setBoards(null);
    api.get("/boards/all")
      .then(r => setBoards(normalizeList(r)))
      .catch(e => setError(e.message))
      .finally(() => setLoading(false));
  }, [api]);

  return (
    <div className="ib-main">
      <div className="home-banner">
        <div>
          <div className="home-banner-title">// imageboard</div>
          <div className="home-banner-sub">выбери доску чтобы начать</div>
        </div>
        {boards && <span className="home-banner-tag">{boards.length} досок</span>}
      </div>

      <div className="section-label">доски</div>

      {loading && <LoadingBlock />}
      {error && <ErrorBlock msg={error} />}
      {!loading && !error && boards?.length === 0 && <EmptyBlock text="нет досок" />}
      {!loading && !error && boards?.length > 0 && (
        <div className="boards-grid">
          {boards.map((b, i) => (
            <div className="board-card" key={b.id ?? i} onClick={() => onBoard(b)}>
              <div className="board-tag">/{getBoardName(b).toLowerCase().replace(/\s+/g, "")}/</div>
              <div className="board-name">{getBoardName(b)}</div>
              {getBoardDesc(b) && <div className="board-desc">{getBoardDesc(b)}</div>}
              <div className="board-meta">
                <span className="board-stat">#{b.id ?? i + 1}</span>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ─── BOARD PAGE ──────────────────────────────────────────────────────────────
function BoardPage({ api, board, onThread }) {
  const [threads, setThreads] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    setLoading(true); setError(null); setThreads(null);
    // Try board-specific endpoint, then fall back to all threads
    const tryBoardEndpoint = api.get(`/boards/${board.id}`)
      .then(r => {
        // Board might embed threads
        const embedded = normalizeList(
          r?.threads ?? r?.data?.threads ?? r?.data ?? r
        );
        if (embedded.length > 0 && embedded[0]?.id !== undefined) return embedded;
        return null;
      })
      .catch(() => null);

    tryBoardEndpoint.then(res => {
      if (res) { setThreads(res); setLoading(false); return; }
      return api.get("/threads/all");
    })
      .then(r => {
        if (r === undefined) return; // already set
        const all = normalizeList(r);
        // Filter by boardId if possible
        const boardId = board.id;
        const filtered = all.filter(t =>
          t.boardId === boardId || t.board_id === boardId
          || t.board?.id === boardId || String(t.boardId) === String(boardId)
        );
        setThreads(filtered.length > 0 ? filtered : all);
      })
      .catch(e => setError(e.message))
      .finally(() => setLoading(false));
  }, [api, board]);

  return (
    <div className="ib-main">
      <div className="page-header">
        <div>
          <div className="page-title">/{getBoardName(board).toLowerCase()}/</div>
          {getBoardDesc(board) && <div className="page-sub">{getBoardDesc(board)}</div>}
        </div>
        {threads && <span className="count-pill">{threads.length} тредов</span>}
      </div>

      <div className="section-label">треды</div>
      {loading && <LoadingBlock />}
      {error && <ErrorBlock msg={error} />}
      {!loading && !error && threads?.length === 0 && <EmptyBlock text="нет тредов" />}
      {!loading && !error && threads?.length > 0 && (
        <div className="thread-list">
          {threads.map((t, i) => (
            <div className="thread-card" key={t.id ?? i} onClick={() => onThread(t)}>
              <div className="thread-num">#{i + 1}</div>
              <div className="thread-body">
                <div className="thread-title">{getThreadTitle(t)}</div>
                {getThreadPreview(t) && (
                  <div className="thread-preview">{getThreadPreview(t)}</div>
                )}
              </div>
              <div className="thread-arrow">›</div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ─── THREAD PAGE ─────────────────────────────────────────────────────────────
function ThreadPage({ api, thread }) {
  const [posts, setPosts] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    setLoading(true); setError(null); setPosts(null);

    const tryThread = api.get(`/threads/${thread.id}`)
      .then(r => {
        const embedded = normalizeList(r?.posts ?? r?.data?.posts ?? []);
        if (embedded.length > 0) return embedded;
        // Thread itself might be the only post
        return null;
      })
      .catch(() => null);

    tryThread.then(res => {
      if (res) { setPosts(res); setLoading(false); return; }
      return api.get("/posts/all");
    })
      .then(r => {
        if (r === undefined) return;
        const all = normalizeList(r);
        const threadId = thread.id;
        const filtered = all.filter(p =>
          p.threadId === threadId || p.thread_id === threadId
          || p.thread?.id === threadId || String(p.threadId) === String(threadId)
        );
        setPosts(filtered.length > 0 ? filtered : all);
      })
      .catch(e => setError(e.message))
      .finally(() => setLoading(false));
  }, [api, thread]);

  return (
    <div className="ib-main">
      <div className="page-header">
        <div>
          <div className="page-title">{getThreadTitle(thread)}</div>
          {getThreadPreview(thread) && (
            <div className="page-sub">{getThreadPreview(thread)}</div>
          )}
        </div>
        {posts && <span className="count-pill">{posts.length} постов</span>}
      </div>

      <div className="section-label">посты</div>
      {loading && <LoadingBlock />}
      {error && <ErrorBlock msg={error} />}
      {!loading && !error && posts?.length === 0 && <EmptyBlock text="нет постов" />}
      {!loading && !error && posts?.length > 0 && (
        <div className="post-list">
          {posts.map((p, i) => (
            <div className="post-card" key={p.id ?? i}>
              <div className="post-head">
                <span className="post-author">{getAuthor(p)}</span>
                <span className="post-no">No.{p.id ?? i + 1}</span>
                {(p.createdAt || p.created_at || p.date || p.timestamp) && (
                  <span className="post-date">
                    {formatDate(p.createdAt ?? p.created_at ?? p.date ?? p.timestamp)}
                  </span>
                )}
              </div>
              <PostBody text={getPostBody(p) || "(пустой пост)"} />
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ─── ADMIN PANEL ─────────────────────────────────────────────────────────────
function AdminPanel({ baseUrl, setBaseUrl }) {
  const [ids, setIds] = useState({});
  const [response, setResponse] = useState(null);
  const [loading, setLoading] = useState(false);
  const [lastReq, setLastReq] = useState("");

  const handleRequest = async (method, pathTemplate, sectionName) => {
    let path = pathTemplate;
    if (path.includes("{id}")) {
      const id = ids[sectionName] || "";
      if (!id.trim()) { alert("Введите ID"); return; }
      path = path.replace("{id}", id.trim());
    }
    const url = baseUrl.replace(/\/$/, "") + path;
    setLastReq(`${method} ${url}`);
    setLoading(true); setResponse(null);
    try {
      const opts = { method, headers: { "Content-Type": "application/json" } };
      if (method === "POST") opts.body = "{}";
      const res = await fetch(url, opts);
      const ct = res.headers.get("content-type") || "";
      let body;
      if (ct.includes("json")) {
        const json = await res.json();
        body = JSON.stringify(json, null, 2);
      } else {
        body = await res.text();
      }
      setResponse({ status: res.status, ok: res.ok, body: body || "(пустой ответ)" });
    } catch (e) {
      setResponse({ status: "error", ok: false, body: "Ошибка: " + e.message });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="app">
      <div className="top-bar">
        <span className="badge badge-get">BASE URL</span>
        <input
          className="base-input"
          value={baseUrl}
          onChange={(e) => setBaseUrl(e.target.value)}
          placeholder="http://localhost:8080"
        />
      </div>
      <div className="sections">
        {SECTIONS.map((section) => (
          <div className="section" key={section.name}>
            <div className="section-title">
              <span className="dot" style={{ background: section.color }} />
              {section.name}
            </div>
            {section.endpoints.map((ep) => (
              <div className="btn-row" key={ep.path}>
                <span className={`badge ${ep.method === "GET" ? "badge-get" : "badge-post"}`}>
                  {ep.method}
                </span>
                <button
                  className="endpoint-btn"
                  onClick={() => handleRequest(ep.method, ep.path, section.name)}
                >
                  {ep.path}
                </button>
                {ep.hasId && (
                  <input
                    className="id-input"
                    placeholder="id"
                    value={ids[section.name] || ""}
                    onChange={(e) => setIds((prev) => ({ ...prev, [section.name]: e.target.value }))}
                  />
                )}
              </div>
            ))}
          </div>
        ))}
      </div>
      <div className="response-area">
        <div className="response-header">
          <span className="response-label">response</span>
          <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
            {response && (
              <span className={`status-pill ${response.ok ? "status-ok" : "status-err"}`}>
                {response.status}
              </span>
            )}
            {!response && !loading && <span className="status-pill status-idle">idle</span>}
            {loading && <span className="status-pill status-idle">...</span>}
            <button className="clear-btn" onClick={() => { setResponse(null); setLastReq(""); }}>
              clear
            </button>
          </div>
        </div>
        {lastReq && <div className="req-line">{lastReq}</div>}
        <pre className="response-body" style={{ color: loading ? "var(--muted)" : response?.ok === false ? "var(--danger)" : "var(--text)" }}>
          {loading ? "Загрузка..." : response?.body ?? "Нажми кнопку чтобы отправить запрос..."}
        </pre>
      </div>
    </div>
  );
}

// ─── ROOT APP ─────────────────────────────────────────────────────────────────
export default function App() {
  const [baseUrl, setBaseUrl] = useState(DEFAULT_BASE);
  // view: "home" | "board" | "thread" | "admin"
  const [view, setView] = useState("home");
  const [currentBoard, setCurrentBoard] = useState(null);
  const [currentThread, setCurrentThread] = useState(null);

  const api = useApi(baseUrl);

  const goHome = () => { setView("home"); setCurrentBoard(null); setCurrentThread(null); };
  const goBoard = (b) => { setCurrentBoard(b); setCurrentThread(null); setView("board"); };
  const goThread = (t) => { setCurrentThread(t); setView("thread"); };

  // Breadcrumb segments
  const crumbs = [];
  if (view !== "home" && view !== "admin") {
    crumbs.push({ label: "home", action: goHome });
  }
  if ((view === "board" || view === "thread") && currentBoard) {
    crumbs.push({ label: `/${getBoardName(currentBoard).toLowerCase()}/`, action: () => goBoard(currentBoard) });
  }
  if (view === "thread" && currentThread) {
    crumbs.push({ label: getThreadTitle(currentThread), action: null });
  }

  return (
    <>
      <style>{styles}</style>

      {/* HEADER */}
      <div className="ib-header">
        <div className="ib-header-inner">
          <div className="ib-logo" onClick={goHome}>
            //<span>img</span>board
          </div>

          {crumbs.length > 0 && (
            <div className="ib-breadcrumb">
              {crumbs.map((c, i) => (
                <span key={i} style={{ display: "flex", alignItems: "center", gap: 4, minWidth: 0 }}>
                  {i > 0 && <span className="ib-breadcrumb-sep">›</span>}
                  {c.action
                    ? <span className="ib-breadcrumb-link" onClick={c.action}>{c.label}</span>
                    : <span className="ib-breadcrumb-cur">{c.label}</span>
                  }
                </span>
              ))}
            </div>
          )}

          <div className="ib-nav-spacer" />
          <div className="ib-nav-tabs">
            <button className={`ib-tab ${view === "home" ? "active" : ""}`} onClick={goHome}>boards</button>
            <button className={`ib-tab ${view === "admin" ? "active" : ""}`} onClick={() => setView("admin")}>admin</button>
          </div>
        </div>
      </div>

      {/* PAGES */}
      {view === "home" && <HomePage api={api} onBoard={goBoard} />}
      {view === "board" && currentBoard && <BoardPage api={api} board={currentBoard} onThread={goThread} />}
      {view === "thread" && currentThread && <ThreadPage api={api} thread={currentThread} />}
      {view === "admin" && <AdminPanel baseUrl={baseUrl} setBaseUrl={setBaseUrl} />}
    </>
  );
}
